<article class="dispatch-card" draggable="true" data-job="<?=$j['id']?>"><strong><?=e($j['job_number'])?></strong><span><?=e($j['customer_name'])?></span><small><?=e($j['address1'])?>, <?=e($j['city'])?></small><select class="form-select form-select-sm mt-2 tech-select" aria-label="Technician"><option value="">Crew leader/default</option><?php foreach($technicians as $t):?><option value="<?=$t['id']?>" <?=selected($j['assigned_user_id'],$t['id'])?>><?=e($t['name'])?></option><?php endforeach?></select><select class="form-select form-select-sm mt-2 vehicle-select" aria-label="Vehicle"><option value="">Crew/default vehicle</option><?php foreach($vehicles as $v):?><option value="<?=$v['id']?>" <?=selected($j['assigned_vehicle_id'],$v['id'])?>><?=e($v['unit_number'])?></option><?php endforeach?></select></article>
